var special={type:"likes",prices:{},percents:{},percentsVals:{},userCityId:null,init:function(){$(".form-control").click(function(){special.calculateSum()}).change(function(){special.calculateSum()}).keyup(function(){special.calculateSum()});special.calculateSum()},calculateSum:function(){var e=parseFloat($("#i_header_balance").html().replace(" ",""));var p=$("input[name='type']:checked").val();var j=0;var l=0;var r=$("#i_sex").val();var m=$('select[name="ageFrom"]').val();var n=$('select[name="ageTo"]').val();var f=$('select[name="city"] > option:selected');var h=$("#i_relation").val();var q=$("#i_avatarCount").val();var k=$("#i_filled").val();var g=$("#i_pageAge").val();var o=$("#i_followersCount").val();var c=$("#i_interestingPage").val();var d=$("#i_frequencyPost").val();var b=$("#i_check_prior").prop("checked");var a=$("#i_task_minKarma > option:selected").val();for(i in special.prices){if(i===p){j=special.prices[i]}}j*=$("#i_task_count").val();l=j;if(b){if(special.percents.percent_prior>0){l+=(j*special.percents.percent_prior/100)}}if(r>0){if(special.percentsVals.sex[r]>0){l+=(j*special.percentsVals.sex[r]/100)}else{l+=(j*special.percents.percent_sex/100)}}if(m>0){if(special.percentsVals.ageFrom[m]>0){l+=(j*special.percentsVals.ageFrom[m]/100)}else{l+=(j*special.percents.percent_ageFrom/100)}}if(n>0){if(special.percentsVals.ageTo[n]>0){l+=(j*special.percentsVals.ageTo[n]/100)}else{l+=(j*special.percents.percent_ageTo/100)}}if(f.val()>0){if(f.data("type")=="country"){l+=(j*special.percents.percent_country/100)}else{if(parseInt(f.val())===special.userCityId){l+=(j*special.percents.percent_city_my/100)}else{l+=(j*special.percents.percent_city/100)}}}if(h>0){if(special.percentsVals.relation[h]>0){l+=(j*special.percentsVals.relation[h]/100)}else{l+=(j*special.percents.percent_relation/100)}}if(q>0){if(special.percentsVals.avatarCount[q]>0){l+=(j*special.percentsVals.avatarCount[q]/100)}else{l+=(j*special.percents.percent_avatarCount/100)}}if(k>0){if(special.percentsVals.filled[k]>0){l+=(j*special.percentsVals.filled[k]/100)}else{l+=(j*special.percents.percent_filled/100)}}if(g>0){if(special.percentsVals.pageAge[g]>0){l+=(j*special.percentsVals.pageAge[g]/100)}else{l+=(j*special.percents.percent_pageAge/100)}}if(o>0){if(special.percentsVals.followersCount[o]>0){l+=(j*special.percentsVals.followersCount[o]/100)}else{l+=(j*special.percents.percent_followersCount/100)}}if(c>0){if(special.percentsVals.interestingPage[c]>0){l+=(j*special.percentsVals.interestingPage[c]/100)}else{l+=(j*special.percents.percent_interestingPage/100)}}if(d>0){if(special.percentsVals.frequencyPost[d]>0){l+=(j*special.percentsVals.frequencyPost[d]/100)}else{l+=(j*special.percents.percent_frequencyPost/100)}}if(a){if(special.percentsVals.minKarma[a]>0){l+=(j*special.percentsVals.minKarma[a]/100)}}$("#i_task_sum").val(l+" баллов");if(l>e){$("#i_div_sum").addClass("has-error").removeClass("has-success");$("#i_div_sum_result").show();$("#i_button_submit").attr("disabled",true)}else{$("#i_button_submit").attr("disabled",false);$("#i_div_sum_result").hide();$("#i_div_sum").addClass("has-success").removeClass("has-error")}}};$(document).ready(function(){special.init()});